B.a7=new A.o7(0,"intro")
B.P0=new A.S(B.a7,"Why passive voice matters in aviation",'Aviation English relies heavily on the **passive voice**. Maintenance manuals, checklists, and ATC instructions frequently use passive constructions because **the action is more important than who performs it**.\n\nFor example, "The fuel filter must be replaced" is more precise and professional than "You must replace the fuel filter."',null,null,null)
B.eM=new A.o7(3,"animation")
B.Oz=new A.S(B.eM,"See the transformation",null,null,B.qj,null)
B.B=new A.o7(1,"rule")
B.PH=new A.S(B.B,"Formation Rule","**Active:** Subject + **verb** + object\n**Passive:** Object + **be** + past participle (+ by + agent)\n\n**Tense mapping:**\n\u2022 Simple Present \u2192 is/are + V3\n\u2022 Simple Past \u2192 was/were + V3\n\u2022 Must/Should \u2192 must/should + be + V3\n\u2022 Has/Have \u2192 has/have + been + V3",null,null,null)
B.a8=new A.o7(2,"examples")
B.JA=new A.aB(u.d,"Hidrolik pompa, motor taraf\u0131ndan di\u015fli kutusu arac\u0131l\u0131\u011f\u0131yla \xe7al\u0131\u015ft\u0131r\u0131l\u0131r.","is driven")
B.J0=new A.aB("All maintenance tasks must be performed in accordance with the AMM.","T\xfcm bak\u0131m g\xf6revleri AMM'ye uygun \u015fekilde ger\xe7ekle\u015ftirilmelidir.","must be performed")
B.JY=new A.aB("The fuel filter is replaced every 500 flight hours.","Yak\u0131t filtresi her 500 u\xe7u\u015f saatinde de\u011fi\u015ftirilir.","is replaced")
B.J6=new A.aB("Warning notices must be placed in the cockpit before maintenance.","Bak\u0131mdan \xf6nce kokpite uyar\u0131 levhalar\u0131 yerle\u015ftirilmelidir.","must be placed")
B.V3=s([B.JA,B.J0,B.JY,B.J6],t.l)
B.O8=new A.S(B.a8,"Aviation Examples",null,B.V3,null,null)
B.a9=new A.o7(5,"tip")
B.O9=new A.S(B.a9,"\u2708\ufe0f Exam Tip",'In multiple-choice questions, look for clues:\n\u2022 If the subject is a **thing** (not a person), passive is likely correct.\n\u2022 "\u2026\u2026\u2026\u2026 by the engine" \u2192 passive form needed.\n\u2022 Modal verbs + passive: **must be + past participle** is the most common pattern in aviation maintenance English.',null,null,null)
