B.MY=new A.cm("grammar_5","Simple & Continuous Tenses","\u23f0",B.SL)
B.Na=new A.S(B.a7,"Why technical vocabulary matters",'Aviation exams test your ability to understand and use precise technical terms. A technician saying "the thing that lifts the plane" instead of "the **aileron**" is unprofessional and dangerous.\n\nThis lesson covers the most frequently tested components grouped by aircraft system.',null,null,null)
B.Oo=new A.S(B.B,"\ud83d\udee9\ufe0f Flight Control Surfaces","**Ailerons** \u2014 on the wings; control roll (bank left/right)\n**Elevator** \u2014 on the horizontal stabilizer; controls pitch (nose up/down)\n**Rudder** \u2014 on the vertical stabilizer; controls yaw (nose left/right)\n**Flaps** \u2014 on wing trailing edge; increase lift and drag during takeoff/landing\n**Spoilers** \u2014 on wings; reduce lift, increase drag, assist in roll control",null,null,null)
B.Nd=new A.S(B.B,"\u2699\ufe0f Powerplant & Fuel Systems","**Turbine engine** \u2014 compressor \u2192 combustion chamber \u2192 turbine \u2192 nozzle\n**HP fuel shutoff valve** \u2014 high-pressure fuel control valve\n**Fuel manifold** \u2014 distributes fuel to combustion chambers\n**Gearbox** \u2014 transfers power between engine components\n**Nacelle** \u2014 streamlined housing enclosing the engine",null,null,null)
B.Pw=new A.S(B.B,"\ud83d\udd27 Hydraulic & Landing Gear","**Hydraulic actuator** \u2014 converts hydraulic pressure to mechanical movement\n**Hydraulic pump** \u2014 pressurizes hydraulic fluid\n**Landing gear strut** \u2014 shock-absorbing leg of landing gear\n**Torque link** \u2014 scissors linkage preventing wheel rotation on strut\n**Brake assembly** \u2014 disc brakes on main landing gear wheels",null,null,null)
B.IZ=new A.aB("The ailerons deflect differentially to produce a rolling moment.","Eleronlar, yuvarlanma momenti \xfcretmek i\xe7in farkl\u0131 a\xe7\u0131larda sapma yapar.","ailerons")
B.Js=new A.aB(u.d,"Hidrolik pompa, motor taraf\u0131ndan di\u015fli kutusu arac\u0131l\u0131\u011f\u0131yla tahrik edilir.","hydraulic pump")
B.IU=new A.aB("Flap extension increases the camber of the wing and generates additional lift.","Flap a\xe7\u0131l\u0131m\u0131 kanat kavisini art\u0131r\u0131r ve ilave kald\u0131rma kuvveti \xfcretir.","Flap extension")
