B.Pk=new A.S(B.a7,"ATIS delivers critical pre-flight information","ATIS (Automatic Terminal Information Service) broadcasts updated airport information continuously. Pilots must obtain the current ATIS information before contacting ATC and must confirm they have received it with the ATIS letter (Alpha, Bravo, Charlie\u2026).\n\nReading comprehension questions often use ATIS-style texts and ask you to extract specific information.",null,null,null)
B.No=new A.S(B.B,"\ud83d\udcfb Standard ATIS Content",'An ATIS broadcast includes (in order):\n1. Airport name and ATIS information letter\n2. Observation time\n3. Active runway(s) in use\n4. Approach type in use (ILS/VOR/Visual)\n5. Wind direction and speed\n6. Visibility\n7. Weather phenomena\n8. Cloud layers\n9. Temperature and dewpoint\n10. QNH\n11. NOTAMs/special notices\n12. "Advise on initial contact you have information [letter]"',null,null,null)
B.JK=new A.aB("Istanbul Atat\xfcrk information Alpha. Time 0650 UTC. Runway in use: 36L for landing, 36R for takeoff.","\u0130stanbul Atat\xfcrk, bilgi Alfa. Saat 0650 UTC. Kullan\u0131lan pist: ini\u015f i\xe7in 36L, kalk\u0131\u015f i\xe7in 36R.","information Alpha")
B.Jb=new A.aB("ILS approach in use for runway 36L. Transition level: FL60.","Pist 36L i\xe7in ILS yakla\u015fmas\u0131 kullan\u0131lmaktad\u0131r. Ge\xe7i\u015f seviyesi: FL60.","Transition level")
B.Jt=new A.aB("Advise on initial contact you have information Alpha.","\u0130lk temasta Alfa bilgisine sahip oldu\u011funuzu belirtin.","initial contact")
