B.Jm=new A.aB("A TCAS Resolution Advisory directed the crew to climb immediately.","Bir TCAS \xc7\xf6z\xfcm Tavsiyesi, ekibi hemen t\u0131rmanmaya y\xf6neltti.","Resolution Advisory")
B.IV=new A.aB("The IRS requires an alignment period of approximately 10 minutes before departure.","IRS, kalk\u0131\u015ftan \xf6nce yakla\u015f\u0131k 10 dakikal\u0131k bir hizalama s\xfcresi gerektirir.","alignment period")
