B.U5=s(["activate","fire","discharge","release"],t.s)
B.a0d=new A.a5(-232,B.ay,782,"If the first fire extinguisher agent does not extinguish the fire, the crew should \u2026\u2026\u2026\u2026 the second bottle.",B.U5,2,B.z,null,null,null)
B.VX=s(["stall","surge","failure","seizure"],t.s)
B.a05=new A.a5(-233,B.ay,783,"A compressor stall in a jet engine is also known as a compressor \u2026\u2026\u2026\u2026.",B.VX,1,B.aQ,null,null,null)
