B.Vq=s(["In accordance with SOPs","Violating or not following SOPs","Similar to SOPs in other companies","An improvement over SOPs"],t.s)
B.a0W=new A.a5(-301,B.b0,461,'"Contrary to standard operating procedures" means:',B.Vq,1,B.z,null,null,null)
B.Vj=s(["The main cause was crew rest","Crew rest was one element that made the accident more likely","Crew rest alone caused the accident","The crew rested adequately"],t.s)
B.a0R=new A.a5(-302,B.b0,462,'"A contributing factor was the inadequate crew rest period." This means:',B.Vj,1,B.z,null,null,null)
B.S8=s(["It is confirmed that","There was not enough evidence to establish","It is unlikely that","The investigation did not examine"],t.s)
B.a0B=new A.a5(-303,B.b0,463,'"It could not be determined whether\u2026" in a report means:',B.S8,1,B.aQ,null,null,null)
